import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// 一、世界环境层 (World Layer)
const WorldLayerSchema = z.object({
  当前日期: z.string().prefault('2026年1月1日'),
  当前时间: z.string().prefault('12:00'),
  天气现状: z.string().prefault('🌞晴天'),
  当前世界: z.string().prefault('主世界_001'),
  所在国家: z.string().prefault('龙国'),
  具体位置: z.string().prefault('未知地点-待定位')
}).prefault({});

// 二、玩家系统 (Player)
const PlayerSchema = z.object({
  基本信息: z.object({
    姓名: z.string().prefault('旅行者'),
    性别: z.enum(['男', '女']).prefault('男'),
    服饰: z.string().prefault('普通休闲装')
  }).prefault({}),

  身份栏: z.record(
    z.string(),
    z.object({
      身份名称: z.string(),
      身份简介: z.string()
    })
  ).prefault({}),

  背包栏: z.record(
    z.string(),
    z.object({
      物品名称: z.string(),
      物品简介: z.string(),
      物品数量: z.coerce.number().transform(v => Math.max(0, v)).prefault(1)
    })
  ).prefault({}),

  玩家规则栏: z.record(
    z.string(),
    z.object({
      规则名字: z.string(),
      规则效果: z.string()
    })
  ).prefault({})
}).prefault({});

// 三、角色系统 (Companions)
const CompanionSchema = z.object({
  个人信息: z.object({
    姓名: z.string().prefault('未命名角色'),
    性别: z.enum(['男', '女']).prefault('女'),
    种族: z.string().prefault('人类'),
    外号: z.string().prefault('无'),
    性格: z.string().prefault('待观察'),
    来源世界: z.string().prefault('主世界_001'),
    当前位置: z.string().prefault('未知'),
    关系: z.string().prefault('路人')
  }).prefault({}),

  身份栏: z.record(
    z.string(),
    z.object({
      身份名称: z.string(),
      身份简介: z.string()
    })
  ).prefault({}),

  标签栏: z.record(
    z.string(),
    z.object({
      标签名字: z.string(),
      标签简介: z.string()
    })
  ).prefault({}),

  背包栏: z.record(
    z.string(),
    z.object({
      物品名称: z.string(),
      物品简介: z.string(),
      物品数量: z.coerce.number().transform(v => Math.max(0, v)).prefault(1)
    })
  ).prefault({}),

  个人规则栏: z.record(
    z.string(),
    z.object({
      规则名字: z.string(),
      规则效果: z.string()
    })
  ).prefault({}),

  外貌: z.object({
    衣着: z.object({
      上衣: z.string().prefault('待描述'),
      裤子: z.string().prefault('待描述'),
      内衣: z.string().prefault('待描述'),
      内裤: z.string().prefault('待描述'),
      饰品: z.string().prefault('无')
    }).prefault({}),
    身材: z.string().prefault('待描述'),
    性器官: z.object({
      乳房: z.string().prefault('待描述'),
      小穴: z.string().prefault('待描述'),
      屁眼: z.string().prefault('待描述'),
      嘴巴: z.string().prefault('待描述')
    }).prefault({})
  }).prefault({}),

  内心想法: z.string().prefault('内心平静'),
  当前行为: z.string().prefault('站立中'),
  当前姿势: z.string().prefault('自然站姿'),
  个人简介: z.string().prefault('待补充')
}).prefault({});

// 四、世界系统 (Dimension)
const DimensionSchema = z.object({
  世界基本信息: z.object({
    世界名字: z.string().prefault('主世界'),
    世界编号: z.coerce.number().prefault('001'),
    世界介绍: z.string().prefault('这是一个普通的现实世界'),
    世界改造: z.string().prefault('原版：未进行任何改造'),
    世界动态: z.string().prefault('世界运转正常')
  }).prefault({}),

  通用规则栏: z.record(
    z.string(),
    z.object({
      规则名字: z.string(),
      规则效果: z.string()
    })
  ).prefault({}),

  世界人物栏: z.record(
    z.string(),
    z.object({
      人物名字: z.string(),
      性别: z.enum(['男', '女']),
      当前行为: z.string()
    })
  ).prefault({})
}).prefault({});

// 五、地点系统 (Place)
const PlaceSchema = z.object({
  地点基本信息: z.object({
    地点名字: z.string().prefault('未命名地点'),
    地点所属世界: z.string().prefault('主世界_001'),
    地点介绍: z.string().prefault('待描述'),
    地点动态: z.string().prefault('无特殊动态')
  }).prefault({}),

  地点规则栏: z.record(
    z.string(),
    z.object({
      规则名字: z.string(),
      规则效果: z.string()
    })
  ).prefault({}),

  地点人物栏: z.record(
    z.string(),
    z.object({
      人物名字: z.string(),
      性别: z.enum(['男', '女']),
      当前行为: z.string()
    })
  ).prefault({})
}).prefault({});

// 主Schema - 整合所有系统
export const Schema = z.object({
  世界环境层: WorldLayerSchema,
  玩家系统: PlayerSchema,
  角色系统: z.record(z.string(), CompanionSchema).prefault({}),
  世界系统: z.record(z.string(), DimensionSchema).prefault({
    '主世界_001': {
      世界基本信息: {
        世界名字: '主世界',
        世界编号: '001',
        世界介绍: '这是一个普通的现实世界',
        世界改造: '原版：未进行任何改造',
        世界动态: '世界运转正常'
      },
      通用规则栏: {},
      世界人物栏: {}
    }
  }),
  地点系统: z.record(z.string(), PlaceSchema).prefault({})
}).prefault({});

$(() => {
  registerMvuSchema(Schema);
})

