<body>
    <div id="app-container">
        <!-- 顶部环境栏 -->
        <div class="env-bar" id="envBar">
            <div style="width:100%; text-align:center; color: #666;">加载中...</div>
        </div>

        <!-- 操作按钮 -->
        <div class="action-bar">
            <button class="action-btn" onclick="openModal('identityModal')"><i class="fas fa-id-card"></i> 添加身份</button>
            <button class="action-btn" onclick="openModal('tagModal')"><i class="fas fa-tag"></i> 添加标签</button>
            <button class="action-btn" onclick="openModal('ruleModal')"><i class="fas fa-gavel"></i> 添加规则</button>
        </div>

        <!-- 主内容滚动区 -->
        <div class="main-content" id="mainContent">
            <!-- 动态内容 -->
        </div>

        <!-- 底部Tab -->
        <div class="bottom-tabs">
            <button class="tab-btn active" onclick="switchTab('player')">
                <i class="fas fa-user"></i>
                <span>玩家</span>
            </button>
            <button class="tab-btn" onclick="switchTab('character')">
                <i class="fas fa-users"></i>
                <span>角色</span>
            </button>
            <button class="tab-btn" onclick="switchTab('location')">
                <i class="fas fa-map-marker-alt"></i>
                <span>地点</span>
            </button>
            <button class="tab-btn" onclick="switchTab('world')">
                <i class="fas fa-globe"></i>
                <span>世界</span>
            </button>
        </div>
    </div>

    <!-- 隐藏的文件输入 -->
    <input type="file" id="avatarInput" class="file-input" accept="image/*">

    <!-- 详情模态框 -->
    <div id="detailModal" class="modal">
        <div class="modal-content">
            <div class="modal-header">
                <span id="detailTitle">详情</span>
                <i class="fas fa-times" onclick="closeModal('detailModal')" style="cursor:pointer;"></i>
            </div>
            <div id="detailBody"></div>
        </div>
    </div>

    <!-- 表单模态框 -->
    <div id="identityModal" class="modal">
        <div class="modal-content">
            <div class="modal-header"><span>添加身份</span><i class="fas fa-times" onclick="closeModal('identityModal')" style="cursor:pointer;"></i></div>
            <div id="identityForm">
                <div class="form-group"><label class="form-label">对象</label><select class="form-select" id="idTarget"><option value="player">玩家</option></select></div>
                <div class="form-group"><label class="form-label">身份名称</label><input type="text" class="form-input" id="idName" placeholder="例如：圣樱学院老师"></div>
                <div class="form-group"><label class="form-label">身份简介</label><textarea class="form-textarea" id="idDesc" placeholder="描述权限与职责"></textarea></div>
                <button class="form-btn" onclick="submitForm('identity')">确认添加</button>
            </div>
        </div>
    </div>

    <div id="tagModal" class="modal">
        <div class="modal-content">
            <div class="modal-header"><span>添加标签</span><i class="fas fa-times" onclick="closeModal('tagModal')" style="cursor:pointer;"></i></div>
            <div id="tagForm">
                <div class="form-group"><label class="form-label">对象</label><select class="form-select" id="tagTarget"></select></div>
                <div class="form-group"><label class="form-label">标签名称</label><input type="text" class="form-input" id="tagName" placeholder="例如：母狗"></div>
                <div class="form-group"><label class="form-label">标签简介</label><textarea class="form-textarea" id="tagDesc" placeholder="描述标签对角色的影响"></textarea></div>
                <button class="form-btn" onclick="submitForm('tag')">确认添加</button>
            </div>
        </div>
    </div>

    <div id="ruleModal" class="modal">
        <div class="modal-content">
            <div class="modal-header"><span>添加规则</span><i class="fas fa-times" onclick="closeModal('ruleModal')" style="cursor:pointer;"></i></div>
            <div id="ruleForm">
                <div class="form-group"><label class="form-label">类型</label><select class="form-select" id="ruleType" onchange="updateRuleTarget()"><option value="personal">个人规则</option><option value="location">地点规则</option><option value="universal">通用规则</option><option value="player">玩家规则</option></select></div>
                <div class="form-group"><label class="form-label">对象/范围</label><select class="form-select" id="ruleTarget"></select></div>
                <div class="form-group"><label class="form-label">规则名称</label><input type="text" class="form-input" id="ruleName" placeholder="例如：电车之狼"></div>
                <div class="form-group"><label class="form-label">规则效果</label><textarea class="form-textarea" id="ruleEffect" placeholder="详细描述规则效果"></textarea></div>
                <button class="form-btn" onclick="submitForm('rule')">确认添加</button>
            </div>
        </div>
    </div>

    <script>
        // --- 全局状态 ---
        let gameData = null;
        let currentTab = 'player';
        let avatarCache = JSON.parse(localStorage.getItem('worldModAvatars') || '{}');
        let currentEditingId = null;
        // 关键修复：存储折叠状态，避免自动刷新时重置
        let expandedStates = {};

        // --- 数据获取 ---
        function fetchGameData() {
            try {
                const maxId = (typeof getLastMessageId === 'function') ? getLastMessageId() : -1;
                if (maxId === -1) return mockData();

                let targetId = maxId;
                let found = false;
                for (let i = 0; i < 20; i++) {
                    const msgs = getChatMessages(`${targetId}-${targetId}`, {});
                    if (msgs && msgs[0] && msgs[0].role === 'assistant') {
                        found = true;
                        break;
                    }
                    targetId--;
                    if (targetId < 0) break;
                }
                if (!found) targetId = maxId;

                let data = null;
                if (window.Mvu && window.Mvu.getMvuData) {
                    const res = window.Mvu.getMvuData({ type: 'message', message_id: targetId });
                    data = res ? res.stat_data : null;
                } else if (typeof getVariables === 'function') {
                    data = getVariables({ type: 'message', message_id: targetId });
                }

                return data || mockData();
            } catch (e) {
                console.error(e);
                return mockData();
            }
        }

        // Mock Data: 深度增强了角色设定
        function mockData() {
            return {
                世界环境层: { 日期: '2026年1月15日', 时间: '08:05', 天气: '☁️多云', 世界: '主世界_001', 国家: '龙国', 位置: '天辰集团总部-26层总监办' },
                玩家系统: {
                    基本信息: { 姓名: '旅行者', 性别: '男', 服饰: '白衬衫(略有汗渍)' },
                    身份栏: { '市场部专员': { 身份名称: '市场部专员', 身份简介: '天辰集团底层员工，负责跑腿打杂。' } },
                    背包栏: { 'U盘': { 物品名称: 'U盘', 物品数量: 1, 物品简介: '存有连夜赶制的Q2市场计划书。' } },
                    玩家规则栏: {}
                },
                角色系统: {
                    '林静霜': {
                        个人信息: { 姓名: '林静霜', 性别: '女', 关系: '直属上司(表面)/专属母狗(隐性)', 外号: '冰霜女王' },
                        身份栏: { '总监': { 身份名称: '市场部总监', 身份简介: '掌控部门生杀大权的高冷女强人，拥有人事任免权。' } },
                        标签栏: { '舔狗': { 标签名字: '舔狗', 标签简介: '因世界调制，现在对玩家抱有病态的爱慕与顺从。' } },
                        内心想法: '只要是为了他，哪怕在办公室脱光也是荣耀...我是主人的母狗...',
                        当前行为: '跪在办公桌下',
                        当前姿势: 'M字开腿跪姿',
                        个人简介: '曾经是高不可攀的冰山女上司，如今被强制改写了认知。在保留高傲外表的同时，内心已彻底沦陷为玩家的玩物。',
                        个人规则栏: { '内衣达人': { 规则名字: '内衣达人', 规则效果: '在玩家面前只能穿内衣，且认为是最高礼仪。' } },
                        外貌: {
                            衣着: { 内衣: '黑色蕾丝半罩杯Bra', 内裤: '极细丁字裤', 丝袜: '已撕裂的黑丝' },
                            身材: '身高168cm，体重52kg，S型曲线完美，皮肤白皙细腻如瓷，胸围95E罩杯，腰围60cm，臀围92cm，长腿笔直修长。',
                            性器官: {
                                乳房: 'E罩杯爆乳，乳晕呈深红色，乳头因兴奋而坚硬挺立，随着呼吸上下颤动，散发着诱人的奶香。',
                                小穴: '粉嫩紧致，正不断分泌出透明的爱液，大阴唇微微外翻，渴望被粗暴地填满。',
                                屁眼: '紧致的淡褐色菊蕾，从未被开发过，周围皮肤光滑白皙，微微收缩，似乎在期待某种侵犯。',
                                嘴巴: '涂着烈焰红唇，口腔温暖湿润，舌头灵活柔软，喉咙深度惊人，适合深喉服务。'
                            }
                        }
                    }
                },
                地点系统: {
                    '天辰集团': {
                        地点基本信息: { 地点名字: '天辰集团总部', 地点介绍: '龙国顶级财阀的核心枢纽，安保森严。', 地点动态: '早晨8点，员工陆续打卡，无人察觉总监办的异常。' },
                        地点规则栏: { '畅通无阻': { 规则名字: '畅通无阻', 规则效果: '玩家拥有至高权限，可随意进出女厕、更衣室等禁区。' } },
                        地点人物栏: { '林静霜': { 人物名字: '林静霜', 当前行为: '跪在总监办公室' } }
                    }
                },
                世界系统: {
                    '主世界_001': {
                        世界基本信息: { 世界名字: '主世界', 世界介绍: '表面正常的现代都市，实则已被玩家的规则渗透。', 世界改造: '原版：完全按照现实世界设定运行', 世界动态: '龙国经济稳步发展，天辰集团正在进行第二季度市场拓展。' },
                        通用规则栏: { '电车之狼': { 规则名字: '电车之狼', 规则效果: '公共交通上女性无法反抗玩家的猥亵行为。' } },
                        世界人物栏: { '林静霜': { 人物名字: '林静霜', 当前行为: '跪在总监办公室' } }
                    }
                }
            };
        }

        // --- 渲染逻辑 ---

        function render() {
            gameData = fetchGameData();
            renderEnvBar();
            renderContent();
            updateFormOptions();
        }

        function renderEnvBar() {
            const env = gameData.世界环境层 || {};
            const container = document.getElementById('envBar');
            const values = Object.values(env).filter(v => v && typeof v !== 'object');
            let html = '';
            if(env.当前日期) html += `<span><i class="far fa-calendar"></i> ${env.当前日期}</span>`;
            if(env.当前时间) html += `<span><i class="far fa-clock"></i> ${env.当前时间}</span>`;
            if(env.天气现状) html += `<span>${env.天气现状}</span>`;
            if(env.具体位置) html += `<span><i class="fas fa-map-marker-alt"></i> ${env.具体位置}</span>`;
            if(html === '') html = values.join(' | ');
            container.innerHTML = html;
        }

        function renderContent() {
            const container = document.getElementById('mainContent');
            // 关键：不直接清空，而是比对内容或仅在切换tab时清空
            // 简单起见，每次渲染重绘，但通过 expandedStates 恢复状态
            container.innerHTML = '';
            switch (currentTab) {
                case 'player': renderPlayer(container); break;
                case 'character': renderCharacters(container); break;
                case 'location': renderLocations(container); break;
                case 'world': renderWorlds(container); break;
            }
        }

        // Tab: 玩家
        function renderPlayer(container) {
            const p = gameData.玩家系统 || {};
            const info = p.基本信息 || {};
            const name = info.姓名 || '玩家';
            let html = `
                <div class="card">
                    <div class="profile-header">
                        <div class="avatar-box" onclick="changeAvatar('player')">${renderAvatar('player', name)}</div>
                        <div class="profile-info">
                            <div class="info-row"><span style="font-size:14px; color:var(--primary-cyan); font-weight:700;">${name}</span></div>
                            <div class="info-row"><span>性别</span><span class="info-val">${info.性别 || '-'}</span></div>
                            <div class="info-row"><span>服饰</span><span class="info-val">${info.服饰 || '-'}</span></div>
                        </div>
                    </div>
                </div>`;
            html += renderSimpleList('身份列表', p.身份栏, '身份名称', '身份简介', 'fas fa-id-badge');
            html += renderSimpleList('背包物品', p.背包栏, '物品名称', '物品简介', 'fas fa-box');
            html += renderSimpleList('专属规则', p.玩家规则栏, '规则名字', '规则效果', 'fas fa-gavel');
            container.innerHTML = html;
        }

        // Tab: 角色
        function renderCharacters(container) {
            const chars = gameData.角色系统 || {};
            if (Object.keys(chars).length === 0) {
                container.innerHTML = '<div style="text-align:center;padding:20px;color:#666">暂无角色</div>';
                return;
            }
            Object.entries(chars).forEach(([key, char]) => {
                const info = char.个人信息 || {};
                const name = info.姓名 || key;
                let tagsHtml = '';
                if (char.标签栏) Object.values(char.标签栏).forEach(t => tagsHtml += `<span class="tag">${t.标签名字}</span>`);
                if (char.身份栏) Object.values(char.身份栏).forEach(t => tagsHtml += `<span class="tag" style="border-color:var(--primary-cyan);color:var(--primary-cyan)">${t.身份名称}</span>`);

                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="profile-header" onclick="showCharDetail('${key}')" style="cursor:pointer">
                        <div class="avatar-box" style="height:100px; width:60px;">${renderAvatar('char_'+key, name)}</div>
                        <div class="profile-info">
                            <div class="info-row"><span style="color:var(--text-primary);font-weight:700;">${name}</span></div>
                            <div style="margin:4px 0;">${tagsHtml}</div>
                            <div class="item-desc" style="color:var(--primary-purple)">💭 ${char.内心想法 || '...'}</div>
                            <div class="item-desc">🎬 ${char.当前行为 || ''}</div>
                        </div>
                    </div>`;
                container.appendChild(card);
            });
        }

        // Tab: 地点
        function renderLocations(container) {
            const locs = gameData.地点系统 || {};
            Object.values(locs).forEach((loc, index) => {
                const info = loc.地点基本信息 || {};
                const id = `loc_${index}`;
                const isExpanded = expandedStates[id] || false;

                // 预览人物
                let previewHtml = '';
                if (loc.地点人物栏) {
                    Object.values(loc.地点人物栏).forEach(p => {
                        previewHtml += `<div class="preview-char-tag"><i class="fas fa-user" style="font-size:8px"></i> ${p.人物名字}</div>`;
                    });
                }

                // 详细内容
                let detailHtml = `
                    <div class="item-desc" style="margin-bottom:4px;">${info.地点介绍 || ''}</div>
                    <div class="item-desc" style="margin-bottom:8px;color:var(--primary-cyan)">动态: ${info.地点动态 || '无'}</div>
                `;
                if (loc.地点规则栏 && Object.keys(loc.地点规则栏).length > 0) {
                    detailHtml += `<div style="margin-top:4px;padding-top:4px;border-top:1px dashed rgba(255,255,255,0.1)">`;
                    Object.values(loc.地点规则栏).forEach(r => detailHtml += `<div class="item-desc" style="color:var(--primary-pink)">⚠️ [${r.规则名字}] ${r.规则效果}</div>`);
                    detailHtml += `</div>`;
                }
                if (loc.地点人物栏 && Object.keys(loc.地点人物栏).length > 0) {
                    detailHtml += `<div style="margin-top:4px; display:flex; gap:4px; flex-wrap:wrap;">`;
                    Object.values(loc.地点人物栏).forEach(p => detailHtml += `<span class="meta-tag"><i class="fas fa-user"></i> ${p.人物名字}: ${p.当前行为}</span>`);
                    detailHtml += `</div>`;
                }

                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="collapsible-header ${isExpanded ? 'expanded' : ''}" onclick="toggleCollapse('${id}')">
                        <div class="card-title" style="border:none;margin:0;padding:0;"><i class="fas fa-map-marker-alt"></i> ${info.地点名字 || '未知地点'}</div>
                        <div class="preview-chars">${previewHtml}</div>
                        <i class="fas fa-chevron-down chevron-icon" id="icon_${id}"></i>
                    </div>
                    <div class="collapsible-content ${isExpanded ? 'expanded' : ''}" id="${id}">
                        <div style="padding-top:8px; border-top:1px solid rgba(255,255,255,0.05); margin-top:8px;">${detailHtml}</div>
                    </div>`;
                container.appendChild(card);
            });
        }

        // Tab: 世界
        function renderWorlds(container) {
            const worlds = gameData.世界系统 || {};
            Object.values(worlds).forEach((w, index) => {
                const info = w.世界基本信息 || {};
                const id = `world_${index}`;
                const isExpanded = expandedStates[id] || false;

                // 预览人物
                let previewHtml = '';
                if (w.世界人物栏) {
                    Object.values(w.世界人物栏).forEach(p => {
                        previewHtml += `<div class="preview-char-tag"><i class="fas fa-user" style="font-size:8px"></i> ${p.人物名字}</div>`;
                    });
                }

                let detailHtml = `
                    <div class="item-desc">${info.世界介绍}</div>
                    <div class="item-desc" style="margin-top:2px;">改造: ${info.世界改造 || '无'}</div>
                    <div class="item-desc" style="margin-top:4px;color:var(--primary-cyan)">动态: ${info.世界动态}</div>`;

                if (w.通用规则栏 && Object.keys(w.通用规则栏).length > 0) {
                    detailHtml += `<div style="margin-top:6px;">`;
                    Object.values(w.通用规则栏).forEach(r => {
                        detailHtml += `<div class="list-item" style="border-color:var(--primary-purple)"><div class="item-name">${r.规则名字}</div><div class="item-desc">${r.规则效果}</div></div>`;
                    });
                    detailHtml += `</div>`;
                }
                 // 世界人物栏
                if (w.世界人物栏 && Object.keys(w.世界人物栏).length > 0) {
                    detailHtml += `<div style="margin-top:4px; display:flex; gap:4px; flex-wrap:wrap;">`;
                    Object.values(w.世界人物栏).forEach(p => detailHtml += `<span class="meta-tag"><i class="fas fa-user"></i> ${p.人物名字}: ${p.当前行为}</span>`);
                    detailHtml += `</div>`;
                }

                const card = document.createElement('div');
                card.className = 'card';
                card.innerHTML = `
                    <div class="collapsible-header ${isExpanded ? 'expanded' : ''}" onclick="toggleCollapse('${id}')">
                        <div class="card-title" style="border:none;margin:0;padding:0;"><i class="fas fa-globe"></i> ${info.世界名字}</div>
                        <div class="preview-chars">${previewHtml}</div>
                        <i class="fas fa-chevron-down chevron-icon" id="icon_${id}"></i>
                    </div>
                    <div class="collapsible-content ${isExpanded ? 'expanded' : ''}" id="${id}">
                        <div style="padding-top:8px; border-top:1px solid rgba(255,255,255,0.05); margin-top:8px;">${detailHtml}</div>
                    </div>`;
                container.appendChild(card);
            });
        }

        // --- 辅助功能 ---

        function renderSimpleList(title, items, nameK, descK, icon) {
            if(!items || Object.keys(items).length===0) return '';
            let h = `<div class="card"><div class="card-title"><i class="${icon}"></i> ${title}</div>`;
            Object.values(items).forEach(i => h+=`<div class="list-item"><div class="item-name">${i[nameK]}</div><div class="item-desc">${i[descK]}</div></div>`);
            return h + '</div>';
        }

        function toggleCollapse(id) {
            const el = document.getElementById(id);
            const icon = document.getElementById('icon_' + id);
            const isExpanded = el.classList.contains('expanded');

            if (isExpanded) {
                el.classList.remove('expanded');
                icon.style.transform = 'rotate(0deg)';
                expandedStates[id] = false; // 记录状态
            } else {
                el.classList.add('expanded');
                icon.style.transform = 'rotate(180deg)';
                expandedStates[id] = true; // 记录状态
            }
        }

        function switchTab(tab) {
            currentTab = tab;
            document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
            const map = { 'player': 0, 'character': 1, 'location': 2, 'world': 3 };
            document.querySelectorAll('.tab-btn')[map[tab]].classList.add('active');
            renderContent();
        }

        function renderAvatar(id, text) {
            const src = avatarCache[id];
            if (src) return `<img src="${src}" class="avatar-img" alt="${text}">`;
            return `<div class="avatar-placeholder">${text ? text.charAt(0) : '?'}</div>`;
        }

        function changeAvatar(id) {
            currentEditingId = id;
            document.getElementById('avatarInput').click();
        }

        document.getElementById('avatarInput').addEventListener('change', function(e) {
            const file = e.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = function(evt) {
                avatarCache[currentEditingId] = evt.target.result;
                localStorage.setItem('worldModAvatars', JSON.stringify(avatarCache));
                if(document.getElementById('detailModal').classList.contains('active')) {
                     showCharDetail(currentEditingId.replace('char_', ''));
                }
                renderContent();
            };
            reader.readAsDataURL(file);
        });

        // 详情页
        function showCharDetail(key) {
            const char = gameData.角色系统[key];
            const info = char.个人信息 || {};
            const title = document.getElementById('detailTitle');
            const body = document.getElementById('detailBody');

            title.innerText = info.姓名 || key;

            let html = `
                <div class="detail-avatar-large" onclick="changeAvatar('char_${key}')">
                    ${renderAvatar('char_'+key, info.姓名)}
                </div>
            `;

            html += `<div class="card"><div class="card-title">档案</div>`;
            Object.entries(info).forEach(([k,v]) => {
                if(k!=='姓名') html += `<div class="info-row"><span>${k}</span><span class="info-val">${v}</span></div>`;
            });
            html += `</div>`;

            html += `<div class="card"><div class="card-title">当前状态</div>
                <div class="item-desc">💭 ${char.内心想法}</div>
                <div class="item-desc">🎬 ${char.当前行为}</div>
                <div class="item-desc">🧘 ${char.当前姿势}</div>
            </div>`;

            if(char.外貌) {
                html += `<div class="card"><div class="card-title">外貌</div>`;
                if(char.外貌.身材) html += `<div class="item-desc" style="margin-bottom:6px;"><strong>身材：</strong>${char.外貌.身材}</div>`;
                if(char.外貌.衣着) {
                    html += `<div style="margin-bottom:8px;"><div style="font-size:11px;color:var(--text-secondary)">衣着:</div>`;
                    Object.entries(char.外貌.衣着).forEach(([k,v]) => html += `<div style="padding-left:8px;font-size:11px;color:#ccc">${k}: ${v}</div>`);
                    html += `</div>`;
                }
                if(char.外貌.性器官) {
                    html += `<div class="nsfw-box"><div class="nsfw-label">⚠️ 身体密辛 (NSFW)</div>`;
                    Object.entries(char.外貌.性器官).forEach(([k,v]) => {
                        html += `<div style="margin-bottom:4px;"><span style="color:#ff69b4;font-weight:600;">${k}:</span> <span class="nsfw-text">${v}</span></div>`;
                    });
                    html += `</div>`;
                }
                html += `</div>`;
            }

            html += renderSimpleList('身份', char.身份栏, '身份名称', '身份简介', 'fas fa-id-badge');
            html += renderSimpleList('标签', char.标签栏, '标签名字', '标签简介', 'fas fa-tag');
            html += renderSimpleList('个人规则', char.个人规则栏, '规则名字', '规则效果', 'fas fa-gavel');

            html += `<div class="card"><div class="card-title">简介</div><div class="item-desc">${char.个人简介}</div></div>`;

            body.innerHTML = html;
            document.getElementById('detailModal').classList.add('active');
        }

        // 表单逻辑
        function updateFormOptions() {
            if (!gameData) return;
            const idSel = document.getElementById('idTarget');
            idSel.innerHTML = '<option value="player">玩家</option>';
            Object.keys(gameData.角色系统 || {}).forEach(k => idSel.innerHTML += `<option value="${k}">${k}</option>`);

            const tagSel = document.getElementById('tagTarget');
            tagSel.innerHTML = '';
            Object.keys(gameData.角色系统 || {}).forEach(k => tagSel.innerHTML += `<option value="${k}">${k}</option>`);

            updateRuleTarget();
        }

        function updateRuleTarget() {
            if (!gameData) return;
            const type = document.getElementById('ruleType').value;
            const target = document.getElementById('ruleTarget');
            target.innerHTML = '';

            let list = {};
            if(type === 'personal') list = gameData.角色系统 || {};
            else if(type === 'location') list = gameData.地点系统 || {};
            else if(type === 'universal') list = gameData.世界系统 || {};
            else if(type === 'player') { target.innerHTML = '<option value="player">玩家</option>'; return; }

            Object.keys(list).forEach(k => target.innerHTML += `<option value="${k}">${k}</option>`);
        }

        function submitForm(type) {
            let cmd = '';
            if (type === 'identity') {
                const t = document.getElementById('idTarget').value;
                const n = document.getElementById('idName').value;
                const d = document.getElementById('idDesc').value;
                cmd = `给【${t}】添加身份：${n}\n身份简介：${d}`;
                closeModal('identityModal');
            } else if (type === 'tag') {
                const t = document.getElementById('tagTarget').value;
                const n = document.getElementById('tagName').value;
                const d = document.getElementById('tagDesc').value;
                cmd = `给【${t}】添加标签：${n}\n标签简介：${d}`;
                closeModal('tagModal');
            } else if (type === 'rule') {
                const typeVal = document.getElementById('ruleType').value;
                const t = document.getElementById('ruleTarget').value;
                const n = document.getElementById('ruleName').value;
                const e = document.getElementById('ruleEffect').value;
                let typeName = '个人规则';
                if(typeVal==='location') typeName='地点规则';
                if(typeVal==='universal') typeName='通用规则';
                if(typeVal==='player') typeName='玩家规则';
                cmd = `给【${t}】添加${typeName}：${n}\n规则效果：${e}`;
                closeModal('ruleModal');
            }

            const ta = document.createElement('textarea');
            ta.value = cmd;
            document.body.appendChild(ta);
            ta.select();
            document.execCommand('copy');
            document.body.removeChild(ta);
            alert('指令已复制:\n' + cmd);
        }

        window.openModal = (id) => document.getElementById(id).classList.add('active');
        window.closeModal = (id) => document.getElementById(id).classList.remove('active');

        // 启动
        setInterval(render, 5000);
        render();

    </script>
</body>
</html>
```

